import{_ as e,o as a,c as o,ag as r}from"./chunks/framework.BYehg5q7.js";const u=JSON.parse('{"title":"Biological Age","description":"","frontmatter":{},"headers":[],"relativePath":"guide/phenoage.md","filePath":"guide/phenoage.md","lastUpdated":1773398769000}'),i={name:"guide/phenoage.md"};function n(l,t,d,s,h,c){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="biological-age" tabindex="-1">Biological Age <a class="header-anchor" href="#biological-age" aria-label="Permalink to &quot;Biological Age&quot;">​</a></h1><p>Biological age estimates how old your body appears based on blood markers — as opposed to your chronological age. getbased computes it automatically from two published models and presents a single combined result.</p><h2 id="two-clocks-one-number" tabindex="-1">Two Clocks, One Number <a class="header-anchor" href="#two-clocks-one-number" aria-label="Permalink to &quot;Two Clocks, One Number&quot;">​</a></h2><p>getbased calculates biological age using two independently validated models:</p><p><strong>PhenoAge</strong> (Levine et al. 2018) — a mortality-calibrated model using 9 biomarkers. Trained on NHANES III data, it estimates biological age through a mortality risk score. Widely used in longevity research.</p><p><strong>Bortz Age</strong> (Bortz et al. 2023, Nature Communications) — an aging-acceleration model using 22 biomarkers. Trained on UK Biobank data, it estimates how fast your body is aging through a weighted linear combination.</p><p>When both can be calculated, getbased averages them for a more robust estimate. When only one has sufficient inputs, it uses that one. The detail modal shows which components contributed.</p><h2 id="biomarkers" tabindex="-1">Biomarkers <a class="header-anchor" href="#biomarkers" aria-label="Permalink to &quot;Biomarkers&quot;">​</a></h2><h3 id="phenoage-9-markers" tabindex="-1">PhenoAge (9 markers) <a class="header-anchor" href="#phenoage-9-markers" aria-label="Permalink to &quot;PhenoAge (9 markers)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Marker</th><th>Category</th></tr></thead><tbody><tr><td>Albumin</td><td>Protein</td></tr><tr><td>Creatinine</td><td>Kidney</td></tr><tr><td>Glucose</td><td>Metabolic</td></tr><tr><td>CRP</td><td>Inflammation</td></tr><tr><td>Lymphocytes %</td><td>Immune</td></tr><tr><td>MCV</td><td>Hematology</td></tr><tr><td>RDW-CV</td><td>Hematology</td></tr><tr><td>ALP</td><td>Liver</td></tr><tr><td>WBC</td><td>Immune</td></tr></tbody></table><h3 id="bortz-age-22-markers-including-age" tabindex="-1">Bortz Age (22 markers, including age) <a class="header-anchor" href="#bortz-age-22-markers-including-age" aria-label="Permalink to &quot;Bortz Age (22 markers, including age)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Marker</th><th>Category</th></tr></thead><tbody><tr><td>Albumin, ALT, ALP, GGT</td><td>Liver</td></tr><tr><td>Creatinine, Cystatin C, Urea</td><td>Kidney</td></tr><tr><td>Glucose, HbA1c, Total Cholesterol, ApoA-I</td><td>Metabolism</td></tr><tr><td>CRP</td><td>Inflammation</td></tr><tr><td>WBC, RBC, MCV, MCH, RDW</td><td>Hematology</td></tr><tr><td>Neutrophils, Monocytes, Lymphocytes %</td><td>Immune</td></tr><tr><td>SHBG, Vitamin D</td><td>Hormones</td></tr></tbody></table><p>Bortz Age uses more inputs but is more forgiving — a standard CBC + metabolic panel covers most of them. PhenoAge requires all 9 on the same date. Both accept either hs-CRP or standard CRP.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Both models require <strong>all their inputs on the same blood draw date</strong>. If any marker is missing for a given date, no value is calculated. The detail view shows exactly which inputs are missing. Both also require your <strong>date of birth</strong> in Settings → Profile.</p></div><h2 id="where-to-find-it" tabindex="-1">Where to Find It <a class="header-anchor" href="#where-to-find-it" aria-label="Permalink to &quot;Where to Find It&quot;">​</a></h2><p>Biological Age appears in the <strong>Calculated Ratios</strong> category in the sidebar. The chart shows:</p><ul><li>A <strong>solid line</strong> for your Biological Age at each draw date</li><li>A <strong>dashed line</strong> for your chronological age at the time of each draw</li><li>The gap between the two — the key number to watch</li></ul><h2 id="interpreting-your-score" tabindex="-1">Interpreting Your Score <a class="header-anchor" href="#interpreting-your-score" aria-label="Permalink to &quot;Interpreting Your Score&quot;">​</a></h2><p>There is no fixed reference range. What matters is the relationship between your Biological Age and your actual age:</p><ul><li><strong>Biological Age &lt; chronological age</strong> — your body is aging slower than average</li><li><strong>Biological Age = chronological age</strong> — average</li><li><strong>Biological Age &gt; chronological age</strong> — your body is aging faster than average</li></ul><p>The trend over time matters more than any single reading.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The detail modal shows the breakdown — PhenoAge and Bortz Age components, with their individual deltas from chronological age. If only one clock could calculate, it tells you which inputs the other is missing.</p></div><h2 id="hs-crp-hdl-ratio" tabindex="-1">hs-CRP/HDL Ratio <a class="header-anchor" href="#hs-crp-hdl-ratio" aria-label="Permalink to &quot;hs-CRP/HDL Ratio&quot;">​</a></h2><p>Also in Calculated Ratios, this composite marker divides hs-CRP (inflammation) by HDL cholesterol (protection). It captures cardiovascular risk better than either marker alone — a patient can have mildly elevated CRP and borderline-low HDL, each unremarkable alone, but the ratio reveals a pro-atherogenic state.</p><table tabindex="0"><thead><tr><th>Risk</th><th>Ratio</th></tr></thead><tbody><tr><td>Optimal</td><td>&lt; 0.24</td></tr><tr><td>Normal</td><td>&lt; 0.94</td></tr><tr><td>Elevated</td><td>&gt; 0.94</td></tr></tbody></table><p>This ratio requires hs-CRP specifically (standard CRP lacks precision at low values).</p><h2 id="in-ai-chat" tabindex="-1">In AI Chat <a class="header-anchor" href="#in-ai-chat" aria-label="Permalink to &quot;In AI Chat&quot;">​</a></h2><p>When you discuss Biological Age in the AI chat, the AI receives both component scores alongside your chronological age and can interpret the gap, note the trend, and suggest which contributing markers to focus on.</p><h2 id="attribution" tabindex="-1">Attribution <a class="header-anchor" href="#attribution" aria-label="Permalink to &quot;Attribution&quot;">​</a></h2><p>The Biological Age implementation was inspired by the <a href="https://longevityworldcup.com" target="_blank" rel="noreferrer">Longevity World Cup</a> project. Bortz Age coefficients sourced from their open implementation of the Bortz et al. 2023 model.</p>',30)])])}const m=e(i,[["render",n]]);export{u as __pageData,m as default};
